// Petstore Client — drive the generated byte-native TypeScript client.
//
// The generated client imports the transport runtime from "@endjin/corvus-json-client-runtime"
// and the models from "./models/generated.js". In this playground there is no live server, so the
// playground stubs globalThis.fetch with canned responses (see the mock transport in the run engine);
// FetchApiTransport then works entirely offline.
import { FetchApiTransport } from "@endjin/corvus-json-client-runtime";
import { ApiPetsClient } from "./ApiPetsClient.js";
import type { Pet } from "./models/generated.js";

// ── Setting up the client ────────────────────────────────────────────────────
// The base URL carries the spec's server path prefix (/v1); the per-operation path is appended to it.
const transport = new FetchApiTransport({ baseUrl: "https://petstore.example.com/v1" });
const client = new ApiPetsClient(transport);

// ── 1. List pets (GET /pets) ─────────────────────────────────────────────────
console.log("1. Listing pets (limit=10)...");
const listResponse = await client.listPets({ limit: 10 });
listResponse.match({
  ok: (pets: Pet[]) => {
    console.log(`   Got ${pets.length} pets`);
    for (const pet of pets) {
      console.log(`   - [${pet.id}] ${pet.name} (tag: ${pet.tag ?? "none"})`);
    }
  },
  default: (error) => {
    console.error(`   Error ${error.code}: ${error.message}`);
  },
});

// The x-next response header is typed — it links to the next page.
const nextPage = listResponse.xNextHeader;
if (nextPage !== undefined) {
  console.log(`   Next page: ${nextPage}`);
}

// ── 2. Create a pet (POST /pets) ─────────────────────────────────────────────
console.log("2. Creating a pet...");
const createResponse = await client.createPet({ name: "Fido", tag: "dog" });
createResponse.match({
  created: (createdPet: Pet) => {
    console.log(`   Created: [${createdPet.id}] ${createdPet.name} (tag: ${createdPet.tag ?? "none"})`);
  },
  default: (error) => {
    console.error(`   Error ${error.code}: ${error.message}`);
  },
});

// ── 3. Show a specific pet (GET /pets/{petId}) ───────────────────────────────
console.log("3. Showing pet by id...");
const showResponse = await client.showPetById({ petId: "pet-123" });
showResponse.match({
  ok: (foundPet: Pet) => {
    console.log(`   Found: [${foundPet.id}] ${foundPet.name} (tag: ${foundPet.tag ?? "none"})`);
  },
  default: (error) => {
    console.error(`   Error ${error.code}: ${error.message}`);
  },
});

console.log("Done!");